from link_header import Link, parse_link_header
from page_client import collect_items


def test_relation_survives_descriptive_metadata():
    value = (
        '<catalog?page=2&fields=id,name>; '
        'title="recent, reviewed"; rel="next"'
    )

    assert parse_link_header(value) == (
        Link(
            "catalog?page=2&fields=id,name",
            ("next",),
        ),
    )


def test_collection_follows_the_service_location():
    pages = {
        "https://api.example.test/v1/catalog?page=1": (
            '{"items": [{"id": 1}]}',
            {"Link": '</v1/catalog?page=2>; rel="next"'},
        ),
        "https://api.example.test/v1/catalog?page=2": (
            '{"items": [{"id": 2}]}',
            {},
        ),
    }

    assert collect_items(
        "https://api.example.test/v1/catalog?page=1",
        pages.__getitem__,
    ) == ({"id": 1}, {"id": 2})
